import { useEffect, useState } from "react";

function App() {
  const [questions, setQuestions] = useState([]);

  useEffect(() => {
    fetch("/api/quiz")
      .then(res => res.json())
      .then(data => setQuestions(data));
  }, []);

  return (
    <div style={{ padding: "20px" }}>
      <h1>Online Exam - v1</h1>
      <h3>Harshith B - 23MIS0012</h3>

      {questions.map(q => (
        <div key={q.id} style={{ marginBottom: "20px" }}>
          <p>{q.question}</p>
          {q.options.map(opt => (
            <div key={opt}>{opt}</div>
          ))}
        </div>
      ))}
    </div>
  );
}

export default App;
